using System.Globalization;using System.Text.RegularExpressions;using GmpCompanyCollector.App.Models;
namespace GmpCompanyCollector.App.Utilities;
public static class TextCleaner{static readonly Regex Ws=new("\\s+",RegexOptions.Compiled); public static string Clean(string? s)=>Ws.Replace((s??"").Replace('\n',' ').Replace('\r',' ').Trim()," ");}
public static class DateParser{public static (string Display,bool Valid) Parse(string? raw){raw=TextCleaner.Clean(raw); return raw.Length==8&&DateTime.TryParseExact(raw,"yyyyMMdd",CultureInfo.InvariantCulture,DateTimeStyles.None,out var d)?(d.ToString("yyyy-MM-dd"),true):(raw,false);} }
public static class CompanyNameNormalizer{static readonly Regex Corp=new("(주식회사|㈜|\\(주\\)|（주）|\\( 주 \\))",RegexOptions.Compiled); public static string Normalize(string? n)=>TextCleaner.Clean(Corp.Replace(n??"","")).Trim();}
public static class AddressParser{static readonly string[] Sidos=["서울특별시","부산광역시","대구광역시","인천광역시","광주광역시","대전광역시","울산광역시","세종특별자치시","경기도","강원특별자치도","강원도","충청북도","충청남도","전북특별자치도","전라북도","전라남도","경상북도","경상남도","제주특별자치도"]; public static (string Sido,string Sigungu) Parse(string? address){var a=TextCleaner.Clean(address); if(a=="")return("",""); var parts=a.Split(' ',StringSplitOptions.RemoveEmptyEntries); var sido=Sidos.FirstOrDefault(s=>a.StartsWith(s))??parts.FirstOrDefault()??""; var sigungu=parts.Skip(1).FirstOrDefault(p=>p.EndsWith('시')||p.EndsWith('군')||p.EndsWith('구'))??""; return(sido,sigungu);} public static string Combine(string? a,string? b){a=TextCleaner.Clean(a);b=TextCleaner.Clean(b);return string.Join(' ',new[]{a,b}.Where(x=>x.Length>0));}}
public static class SensitiveDataMasker{public static string MaskKey(string? k){k=TextCleaner.Clean(k);return k.Length<=8?"****":k[..4]+"****"+k[^4..];} public static string MaskUrl(string? u)=>Regex.Replace(u??"","serviceKey=[^&]+","serviceKey=***",RegexOptions.IgnoreCase);}
public static class ApiUrlBuilder{public const string DefaultBaseUrl="http://apis.data.go.kr/1471000/DrugEtcBsshBspmStusService"; public static bool LooksEncoded(string key)=>Regex.IsMatch(key,"%2B|%2F|%3D|%25",RegexOptions.IgnoreCase); public static Uri Build(string endpoint,CollectionOptions o,int pageNo){var key=TextCleaner.Clean(o.ServiceKey); var encoded=o.KeyMode==ServiceKeyMode.Encoding||(o.KeyMode==ServiceKeyMode.Auto&&LooksEncoded(key)); var pairs=new List<string>{"serviceKey="+(encoded?key:Uri.EscapeDataString(key)),"pageNo="+pageNo,"numOfRows="+o.NumOfRows,"type="+Uri.EscapeDataString(o.Type)}; void add(string n,string v){v=TextCleaner.Clean(v); if(v!="")pairs.Add(n+"="+Uri.EscapeDataString(v));} if(endpoint.Contains("List")){add("Induty",o.Induty);add("Entrps",o.Entrps);add("Prmisn_dt",o.PrmisnDt);} else add("Prmisn_no",o.PrmisnNo); return new Uri($"{DefaultBaseUrl}/{endpoint}?{string.Join('&',pairs)}");} public static int CalculateTotalPages(int total,int rows)=>total<=0||rows<=0?0:(int)Math.Ceiling(total/(double)rows);}
